@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_cd2b5e4a42704c179cbf5b86da219919.Models
@using sv_cd2b5e4a42704c179cbf5b86da219919.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;
    private CancellationTokenSource? _loadCts;
    private int _lastLoadedCuisineId;

    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null)
                return Enumerable.Empty<Recipe>();

            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override Task OnParametersSetAsync()
    {
        // Only reload data when the cuisine changes, not when sort changes
        if (CuisineId != _lastLoadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        await CancelPendingLoadAsync();

        _lastLoadedCuisineId = CuisineId;
        _errorMessage = null;

        // If we already have data, show refreshing indicator instead of full loading state
        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        _loadCts = new CancellationTokenSource();
        var cancellationToken = _loadCts.Token;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cancellationToken);

            if (!cancellationToken.IsCancellationRequested)
            {
                _recipes = results;
                _isRefreshing = false;
            }
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // Expected when navigating away or switching cuisines — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    private async Task CancelPendingLoadAsync()
    {
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
            _loadCts = null;
        }
    }

    public void Dispose()
    {
        _loadCts?.Cancel();
        _loadCts?.Dispose();
        _loadCts = null;
    }
}

